import locale
import sys

def setup_locale(locale_name: str = None) -> bool:
    """设置全局区域，返回是否成功。"""
    try:
        if locale_name:
            locale.setlocale(locale.LC_ALL, locale_name)
        else:
            # 尝试使用用户默认区域
            locale.setlocale(locale.LC_ALL, '')
        return True
    except locale.Error:
        print(f"Warning: Locale '{locale_name}' not available, using default.", file=sys.stderr)
        return False

def format_number(num: float, grouping: bool = True) -> str:
    return locale.format_string('%.2f', num, grouping=grouping)

def format_currency(amount: float) -> str:
    return locale.currency(amount, grouping=True)

# 使用示例
if __name__ == '__main__':
    setup_locale('en_US.UTF-8')
    print(format_number(1234567.89))
    print(format_currency(1234.56))
